import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';

function Home() {
  const [osList, setOsList] = useState([]);
  const [filtroNumero, setFiltroNumero] = useState('');
  const [filtroStatus, setFiltroStatus] = useState('todos');
  const [filtroCliente, setFiltroCliente] = useState('');
  const [pagina, setPagina] = useState(1);
  const itensPorPagina = 10;

  // Estatísticas
  const [totalAbertas, setTotalAbertas] = useState(0);
  const [totalConcluidas, setTotalConcluidas] = useState(0);
  const [faturamentoMes, setFaturamentoMes] = useState(0);

  useEffect(() => {
    carregarOS();
  }, []);

  const carregarOS = async () => {
    try {
      const res = await api.get('/os');
      const data = res.data;
      setOsList(data);
      // Calcular estatísticas
      const abertas = data.filter(os => os.status_os !== 'concluido').length;
      const concluidas = data.filter(os => os.status_os === 'concluido').length;
      const mesAtual = new Date().getMonth();
      const anoAtual = new Date().getFullYear();
      const fatMes = data.reduce((acc, os) => {
        if (os.status_os === 'concluido' && os.data_conclusao) {
          const dataConc = new Date(os.data_conclusao);
          if (dataConc.getMonth() === mesAtual && dataConc.getFullYear() === anoAtual) {
            return acc + (parseFloat(os.preco_final) || 0);
          }
        }
        return acc;
      }, 0);
      setTotalAbertas(abertas);
      setTotalConcluidas(concluidas);
      setFaturamentoMes(fatMes);
    } catch (err) {
      console.error(err);
      setOsList([]);
    }
  };

  const finalizarOS = async (id) => {
    if (window.confirm('Finalizar esta OS?')) {
      try {
        await api.put(`/os/${id}`, { status_os: 'concluido' });
        carregarOS();
      } catch (err) {
        alert('Erro ao finalizar OS');
      }
    }
  };

  // Lógica de filtro e paginação...
  const osFiltradas = osList.filter(os => {
    if (filtroNumero && !os.numero_os?.toLowerCase().includes(filtroNumero.toLowerCase())) return false;
    if (filtroStatus === 'abertos' && os.status_os === 'concluido') return false;
    if (filtroStatus === 'concluidos' && os.status_os !== 'concluido') return false;
    if (filtroCliente && !os.cliente_nome?.toLowerCase().includes(filtroCliente.toLowerCase())) return false;
    return true;
  });
  const totalPaginas = Math.ceil(osFiltradas.length / itensPorPagina);
  const osExibidas = osFiltradas.slice((pagina-1)*itensPorPagina, pagina*itensPorPagina);

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      {/* Título */}
      <div style={{ textAlign: 'center', marginBottom: '30px' }}>
        <h1 style={{ 
          fontSize: '32px', fontWeight: 'bold', textTransform: 'uppercase',
          background: 'linear-gradient(135deg, #1e3c72, #2a5298)', color: 'white',
          padding: '15px', borderRadius: '12px', display: 'inline-block',
          boxShadow: '0 8px 16px rgba(0,0,0,0.2)'
        }}>
          📊 DASHBOARD - MWR SISTEMA
        </h1>
      </div>

      {/* Cards de estatísticas */}
      <div style={{ display: 'flex', gap: '20px', justifyContent: 'center', marginBottom: '30px', flexWrap: 'wrap' }}>
        <div style={{ background: '#fff', padding: '15px', borderRadius: '12px', boxShadow: '0 2px 8px rgba(0,0,0,0.1)', width: '180px', textAlign: 'center' }}>
          <div style={{ fontSize: '2rem' }}>🟠</div>
          <div><strong>OS Abertas</strong></div>
          <div style={{ fontSize: '24px', fontWeight: 'bold' }}>{totalAbertas}</div>
        </div>
        <div style={{ background: '#fff', padding: '15px', borderRadius: '12px', boxShadow: '0 2px 8px rgba(0,0,0,0.1)', width: '180px', textAlign: 'center' }}>
          <div style={{ fontSize: '2rem' }}>✅</div>
          <div><strong>OS Concluídas</strong></div>
          <div style={{ fontSize: '24px', fontWeight: 'bold' }}>{totalConcluidas}</div>
        </div>
        <div style={{ background: '#fff', padding: '15px', borderRadius: '12px', boxShadow: '0 2px 8px rgba(0,0,0,0.1)', width: '180px', textAlign: 'center' }}>
          <div style={{ fontSize: '2rem' }}>💰</div>
          <div><strong>Faturamento (mês)</strong></div>
          <div style={{ fontSize: '24px', fontWeight: 'bold' }}>R$ {faturamentoMes.toFixed(2)}</div>
        </div>
      </div>

      {/* Filtros (igual antes, com estilo melhorado) */}
      <div style={{ display: 'flex', gap: '15px', flexWrap: 'wrap', marginBottom: '25px', background: '#fff', padding: '15px', borderRadius: '12px', boxShadow: '0 1px 4px rgba(0,0,0,0.1)' }}>
        <input type="text" placeholder="🔍 Nº da OS" value={filtroNumero} onChange={e => setFiltroNumero(e.target.value)} style={{ padding: '8px', borderRadius: '6px', border: '1px solid #ccc', flex: 1 }} />
        <select value={filtroStatus} onChange={e => setFiltroStatus(e.target.value)} style={{ padding: '8px', borderRadius: '6px', border: '1px solid #ccc' }}>
          <option value="todos">Todos os status</option>
          <option value="abertos">Somente abertos</option>
          <option value="concluidos">Somente concluídos</option>
        </select>
        <input type="text" placeholder="👤 Nome do cliente" value={filtroCliente} onChange={e => setFiltroCliente(e.target.value)} style={{ padding: '8px', borderRadius: '6px', border: '1px solid #ccc', flex: 1 }} />
      </div>

      {/* Tabela de OS */}
      <div style={{ overflowX: 'auto', borderRadius: '12px', boxShadow: '0 2px 8px rgba(0,0,0,0.1)' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', background: 'white' }}>
          <thead style={{ backgroundColor: '#2c3e50', color: 'white' }}>
            <tr>
              <th style={{ padding: '12px' }}>Nº OS</th>
              <th style={{ padding: '12px' }}>Cliente</th>
              <th style={{ padding: '12px' }}>Equipamento</th>
              <th style={{ padding: '12px' }}>Status</th>
              <th style={{ padding: '12px' }}>Valor (R$)</th>
              <th style={{ padding: '12px' }}>Ações</th>
            </tr>
          </thead>
          <tbody>
            {osExibidas.length === 0 ? (
              <tr><td colSpan="6" style={{ textAlign: 'center', padding: '30px' }}>Nenhuma OS encontrada</td></tr>
            ) : (
              osExibidas.map(os => (
                <tr key={os.id} style={{ borderBottom: '1px solid #eee', backgroundColor: os.status_os === 'concluido' ? '#f8fff8' : '#fff' }}>
                  <td style={{ padding: '10px' }}>{os.numero_os}</td>
                  <td style={{ padding: '10px' }}>{os.cliente_nome}</td>
                  <td style={{ padding: '10px' }}>{os.equipamento} {os.modelo}</td>
                  <td style={{ padding: '10px' }}>
                    <span style={{ backgroundColor: os.status_os === 'concluido' ? '#28a745' : '#ffc107', color: '#000', padding: '4px 8px', borderRadius: '20px', fontSize: '12px', fontWeight: 'bold' }}>
                      {os.status_os === 'concluido' ? 'CONCLUÍDO' : 'ABERTO'}
                    </span>
                  </td>
                  <td style={{ padding: '10px' }}>R$ {parseFloat(os.preco_final || 0).toFixed(2)}</td>
                  <td style={{ padding: '10px' }}>
                    <Link to={`/os/${os.id}`}>
                      <button style={{ marginRight: '5px', padding: '6px 12px', background: '#17a2b8', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>Ver</button>
                    </Link>
                    <Link to={`/os/editar/${os.id}`}>
                      <button style={{ marginRight: '5px', padding: '6px 12px', background: '#ffc107', color: 'black', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>Editar</button>
                    </Link>
                    {os.status_os !== 'concluido' && (
                      <button onClick={() => finalizarOS(os.id)} style={{ padding: '6px 12px', background: '#dc3545', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>Finalizar</button>
                    )}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Paginação */}
      {totalPaginas > 1 && (
        <div style={{ display: 'flex', justifyContent: 'center', gap: '20px', marginTop: '25px' }}>
          <button onClick={() => setPagina(p => Math.max(1, p-1))} disabled={pagina === 1} style={{ padding: '8px 16px', background: '#007bff', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>Anterior</button>
          <span style={{ padding: '8px' }}>Página {pagina} de {totalPaginas}</span>
          <button onClick={() => setPagina(p => Math.min(totalPaginas, p+1))} disabled={pagina === totalPaginas} style={{ padding: '8px 16px', background: '#007bff', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>Próxima</button>
        </div>
      )}
    </div>
  );
}

export default Home;
